```rust
#[test]
async fn test_tcp_connection_refused() {
    // Connect to port nothing is listening on
    let result = TcpStream::connect("127.0.0.1:1").await;
    assert!(result.is_err());
    assert_eq!(result.unwrap_err().kind(), io::ErrorKind::ConnectionRefused);
}
```

### Multiple Accepts

```rust
#[test]
async fn test_tcp_multiple_accepts() {
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();

    let clients: Vec<_> = (0..10)
        .map(|_| TcpStream::connect(addr))
        .collect();

    let servers = async {
        let mut streams = Vec::new();
        for _ in 0..10 {
            let (stream, _) = listener.accept().await.unwrap();
            streams.push(stream);
        }
        streams
    };

    let (clients, servers) = join!(
        futures::future::join_all(clients),
        servers,
    );

    assert_eq!(clients.iter().filter(|r| r.is_ok()).count(), 10);
    assert_eq!(servers.len(), 10);
}
```

## UDP Tests

### Basic Send/Receive

```rust
#[test]
async fn test_udp_send_recv() {
    let server = UdpSocket::bind("127.0.0.1:0").await.unwrap();
    let server_addr = server.local_addr().unwrap();

    let client = UdpSocket::bind("127.0.0.1:0").await.unwrap();

    // Send
    client.send_to(b"hello", &server_addr).await.unwrap();

    // Receive
    let mut buf = [0u8; 10];
    let (n, addr) = server.recv_from(&mut buf).await.unwrap();

    assert_eq!(&buf[..n], b"hello");
    assert_eq!(addr, client.local_addr().unwrap());
}
```

### Connected UDP

```rust
#[test]
async fn test_udp_connected() {
    let a = UdpSocket::bind("127.0.0.1:0").await.unwrap();
    let b = UdpSocket::bind("127.0.0.1:0").await.unwrap();

    a.connect(b.local_addr().unwrap()).await.unwrap();
    b.connect(a.local_addr().unwrap()).await.unwrap();

    a.send(b"ping").await.unwrap();

    let mut buf = [0u8; 10];
    let n = b.recv(&mut buf).await.unwrap();
    assert_eq!(&buf[..n], b"ping");
}
```

