        let output = Command::new("echo")
            .arg("hello")
            .output()
            .await
            .unwrap();

        assert!(output.status.success());
        assert_eq!(output.stdout_string().trim(), "hello");
        debug!(stdout = output.stdout_string().trim(), "Command output");
    }

    #[tokio::test]
    async fn test_command_status() {
        info!("Testing Command::status()");

        let status = Command::new("true")
            .status()
            .await
            .unwrap();

        assert!(status.success());
        assert_eq!(status.code(), Some(0));
    }

    #[tokio::test]
    async fn test_command_failure() {
        info!("Testing command failure");

        let status = Command::new("false")
            .status()
            .await
            .unwrap();

        assert!(!status.success());
        assert_eq!(status.code(), Some(1));
    }

    #[tokio::test]
    async fn test_command_stdin_stdout() {
        info!("Testing stdin/stdout piping");

        let mut child = Command::new("cat")
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .spawn()
            .unwrap();

        let mut stdin = child.take_stdin().unwrap();
        let mut stdout = child.take_stdout().unwrap();

        stdin.write_all(b"hello from stdin").await.unwrap();
        drop(stdin); // Close stdin

        let mut output = String::new();
        stdout.read_to_string(&mut output).await.unwrap();

        assert_eq!(output, "hello from stdin");

        let status = child.wait().await.unwrap();
        assert!(status.success());
    }

